import React, { useState, useEffect, useRef } from 'react';
import './App.css';

// ── Theme Toggle ──────────────────────────────────────────────
const ThemeToggle = ({ darkMode, setDarkMode }) => (
  <button className="theme-toggle" onClick={() => setDarkMode(!darkMode)} aria-label="Toggle theme">
    {darkMode ? (
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
        <circle cx="12" cy="12" r="5"/>
        <line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/>
        <line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/>
        <line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/>
        <line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/>
      </svg>
    ) : (
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
        <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/>
      </svg>
    )}
  </button>
);

// ── Scroll Animation Hook ─────────────────────────────────────
const useScrollAnimation = () => {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setIsVisible(true); },
      { threshold: 0.1, rootMargin: '50px' }
    );
    const el = ref.current;
    if (el) observer.observe(el);
    return () => { if (el) observer.unobserve(el); };
  }, []);
  return [ref, isVisible];
};

// ── Carousel ──────────────────────────────────────────────────
const Carousel = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const images = ['/assets/IMG_2944.jpeg', '/assets/slide2.jpg', '/assets/slide3.jpg'];

  useEffect(() => {
    if (isPaused) return;
    const t = setInterval(() => setCurrentSlide(p => (p + 1) % images.length), 5000);
    return () => clearInterval(t);
  }, [images.length, isPaused]);

  return (
    <div className="carousel" onMouseEnter={() => setIsPaused(true)} onMouseLeave={() => setIsPaused(false)}>
      <div className="carousel-inner" style={{ transform: `translateX(-${currentSlide * 100}%)` }}>
        {images.map((img, i) => (
          <div key={i} className="carousel-slide">
            <img src={img} alt={`Slide ${i + 1}`} loading={i === 0 ? 'eager' : 'lazy'} />
            <div className="carousel-overlay" />
          </div>
        ))}
      </div>
      <button className="carousel-btn prev" onClick={() => setCurrentSlide(p => (p - 1 + images.length) % images.length)} aria-label="Previous slide">
        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="15 18 9 12 15 6"/></svg>
      </button>
      <button className="carousel-btn next" onClick={() => setCurrentSlide(p => (p + 1) % images.length)} aria-label="Next slide">
        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
      <div className="carousel-dots">
        {images.map((_, i) => (
          <button key={i} className={`dot ${currentSlide === i ? 'active' : ''}`} onClick={() => setCurrentSlide(i)} aria-label={`Go to slide ${i + 1}`} />
        ))}
      </div>
    </div>
  );
};

// ── Header ────────────────────────────────────────────────────
const Header = ({ darkMode, setDarkMode }) => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', fn);
    return () => window.removeEventListener('scroll', fn);
  }, []);

  return (
    <header className={`site-header ${scrolled ? 'scrolled' : ''}`}>
      <div className="brand">
        <img src="/assets/IMG_2944.jpeg" alt="MBAM logo" className="MBAM-logo" />
        <div className="brand-text">
          <span className="eyebrow">Muthupet Bayt Ul Mal Al Muslimin</span>
          <h1>MBAM</h1>
        </div>
      </div>
      <button className="mobile-menu-toggle" onClick={() => setMobileMenuOpen(!mobileMenuOpen)} aria-label="Toggle menu">
        <span /><span /><span />
      </button>
      <nav className={`main-nav ${mobileMenuOpen ? 'open' : ''}`}>
        {['About','Projects','Impact','Donate','Contact'].map(item => (
          <a key={item} href={`#${item.toLowerCase()}`} onClick={() => setMobileMenuOpen(false)}>{item}</a>
        ))}
      </nav>
      <div className="header-actions">
        <ThemeToggle darkMode={darkMode} setDarkMode={setDarkMode} />
        <a href="#donate" className="donate-btn">Donate Now</a>
      </div>
    </header>
  );
};

// ── Trust Bar ─────────────────────────────────────────────────
const TrustBar = () => (
  <div className="trust-bar">
    <div className="trust-bar-inner">
      {[
        { icon: '✓', text: 'Registered NGO' },
        { icon: '🛡', text: 'Zakat Approved' },
        { icon: '📋', text: '100% Transparent' },
        { icon: '🤝', text: 'Community Governed' },
        { icon: '📍', text: 'Muthupet, Tamil Nadu' },
      ].map((item, i) => (
        <div key={i} className="trust-item">
          <span className="trust-icon">{item.icon}</span>
          <span>{item.text}</span>
        </div>
      ))}
    </div>
  </div>
);

// ── Hero ──────────────────────────────────────────────────────
const Hero = () => {
  const [ref, isVisible] = useScrollAnimation();
  const [tickerIndex, setTickerIndex] = useState(0);
  const tickers = [
    '🍚 247 meals distributed this week',
    '📚 12 new students enrolled this month',
    '🏠 3 families received emergency relief',
    '💧 Clean water project 68% funded',
  ];

  useEffect(() => {
    const t = setInterval(() => setTickerIndex(p => (p + 1) % tickers.length), 3500);
    return () => clearInterval(t);
  }, [tickers.length]);

  return (
    <section className="hero" ref={ref}>
      <Carousel />
      <div className={`hero-overlay ${isVisible ? 'animate-in' : ''}`}>
        <div className="hero-content">
          <div className="impact-ticker">
            <span className="ticker-dot" />
            <span className="ticker-text">{tickers[tickerIndex]}</span>
          </div>
          <h2>Restoring dignity through compassion and action</h2>
          <p>MBAM supports vulnerable families with food aid, education, and sustainable community programs guided by Islamic values.</p>
          <div className="hero-actions">
            <a href="#donate" className="btn primary">Donate Now</a>
            <a href="#projects" className="btn outline">Our Work</a>
          </div>
        </div>
      </div>
    </section>
  );
};

// ── Quran Section ─────────────────────────────────────────────
const QuranSection = () => {
  const audioRef = useRef(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [ref, isVisible] = useScrollAnimation();

  const togglePlay = () => {
    if (audioRef.current) {
      isPlaying ? audioRef.current.pause() : audioRef.current.play();
      setIsPlaying(!isPlaying);
    }
  };

  return (
    <section className="quran-section">
      <div className={`quran-box ${isVisible ? 'animate-in' : ''}`} ref={ref}>
        <p className="quran-label">Reflection from the Qur'an</p>
        <p className="quran-arabic">
          مَثَلُ الَّذِیْنَ یُنْفِقُوْنَ اَمْوَالَهُمْ فِیْ سَبِیْلِ اللّٰهِ كَمَثَلِ حَبَّةٍ اَنْۢبَتَتْ سَبْعَ سَنَابِلَ فِیْ كُلِّ سُنْۢبُلَةٍ مِّائَةُ حَبَّةٍ
        </p>
        <p className="quran-tamil">
          "(நபியே!) அல்லாஹ்வுடைய பாதையில் தங்கள் பொருள்களைச் செலவு செய்கிறவர்களுடைய உதாரணம், ஒரு வித்தின் உதாரணத்தை ஒத்திருக்கிறது."
        </p>
        <p className="quran-translation">
          "The example of those who spend their wealth in the cause of Allah is that of a grain that sprouts into seven ears, each bearing one hundred grains."
          <span>— Qur'an 2:261</span>
        </p>
        <div className="audio-player">
          <button className="play-button" onClick={togglePlay} aria-label={isPlaying ? 'Pause' : 'Play'}>
            {isPlaying ? (
              <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>
            ) : (
              <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor"><polygon points="5 3 19 12 5 21 5 3"/></svg>
            )}
          </button>
          <audio ref={audioRef} preload="metadata">
            <source src="/assets/quran-261.mp3" type="audio/mpeg" />
          </audio>
        </div>
      </div>
    </section>
  );
};

// ── Mission ───────────────────────────────────────────────────
const Mission = () => {
  const [ref, isVisible] = useScrollAnimation();
  return (
    <section id="about" className="content-section">
      <div className={`section-header ${isVisible ? 'animate-in' : ''}`} ref={ref}>
        <span>Our Mission</span>
        <h3>Charity that creates lasting impact</h3>
      </div>
      <p className={`section-text ${isVisible ? 'animate-in delay-1' : ''}`}>
        We channel generosity into meaningful programs that uplift families, strengthen communities, and protect dignity. Transparency and trust guide every initiative we undertake.
      </p>
    </section>
  );
};

// ── Projects ──────────────────────────────────────────────────
const Projects = () => {
  const [ref, isVisible] = useScrollAnimation();
  const projects = [
    {
      icon: <svg width="44" height="44" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>,
      title: 'Food Assistance', tag: 'Active',
      description: 'Providing essential food supplies to families facing hardship, ensuring no one goes hungry in our community.',
      stat: '500+ families',
    },
    {
      icon: <svg width="44" height="44" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z"/><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z"/></svg>,
      title: 'Education Support', tag: 'Active',
      description: 'Scholarships and learning resources for children and youth to build brighter futures beyond poverty.',
      stat: '250+ students',
    },
    {
      icon: <svg width="44" height="44" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>,
      title: 'Community Care', tag: 'Expanding',
      description: 'Emergency relief and long-term development programs for sustainable, community-driven growth.',
      stat: '12 programs',
    },
  ];

  return (
    <section id="projects" className="content-section light">
      <div className={`section-header ${isVisible ? 'animate-in' : ''}`} ref={ref}>
        <span>Our Work</span>
        <h3>How we help communities</h3>
      </div>
      <div className="cards">
        {projects.map((p, i) => (
          <article key={i} className={isVisible ? `animate-in delay-${i + 1}` : ''}>
            <span className="card-tag">{p.tag}</span>
            <div className="card-icon">{p.icon}</div>
            <h4>{p.title}</h4>
            <p>{p.description}</p>
            <div className="card-stat">{p.stat}</div>
          </article>
        ))}
      </div>
    </section>
  );
};

// ── Stats ─────────────────────────────────────────────────────
const Stats = () => {
  const [ref, isVisible] = useScrollAnimation();
  const [counts, setCounts] = useState({ families: 0, meals: 0, students: 0, years: 0 });

  useEffect(() => {
    if (!isVisible) return;
    const targets = { families: 500, meals: 50000, students: 250, years: 14 };
    const steps = 60;
    const t = setInterval(() => {
      setCounts(prev => ({
        families: Math.min(prev.families + Math.ceil(targets.families / steps), targets.families),
        meals: Math.min(prev.meals + Math.ceil(targets.meals / steps), targets.meals),
        students: Math.min(prev.students + Math.ceil(targets.students / steps), targets.students),
        years: Math.min(prev.years + Math.ceil(targets.years / steps), targets.years),
      }));
    }, 2000 / steps);
    return () => clearInterval(t);
  }, [isVisible]);

  const stats = [
    { value: counts.families.toLocaleString() + '+', label: 'Families Supported', sub: '≈ 2,000 individuals' },
    { value: counts.meals.toLocaleString() + '+', label: 'Meals Distributed', sub: 'across 6 districts' },
    { value: counts.students.toLocaleString() + '+', label: 'Students Educated', sub: 'on full scholarship' },
    { value: counts.years + ' yrs', label: 'Serving Communities', sub: 'since 2010' },
  ];

  return (
    <section className="stats-section" ref={ref}>
      <div className={`stats-grid ${isVisible ? 'animate-in' : ''}`}>
        {stats.map((s, i) => (
          <div key={i} className="stat-item">
            <div className="stat-number">{s.value}</div>
            <div className="stat-label">{s.label}</div>
            <div className="stat-sub">{s.sub}</div>
          </div>
        ))}
      </div>
      <div className={`goal-bar-wrap ${isVisible ? 'animate-in delay-2' : ''}`}>
        <div className="goal-bar-header">
          <span>Goal: 1,000 Families by 2026</span>
          <span>500 / 1,000</span>
        </div>
        <div className="goal-bar-track">
          <div className="goal-bar-fill" style={{ width: isVisible ? '50%' : '0%' }} />
        </div>
        <p className="goal-bar-note">Help us reach the next 500 families — <a href="#donate">donate today</a></p>
      </div>
    </section>
  );
};

// ── Impact Stories ────────────────────────────────────────────
const ImpactStories = () => {
  const [ref, isVisible] = useScrollAnimation();
  const stories = [
    {
      name: 'Fatimah & Family',
      location: 'Muthupet Village',
      before: 'Struggling to afford two meals a day after husband\'s illness left the family without income.',
      after: 'Receiving weekly food aid and children enrolled in MBAM scholarship program.',
      avatar: 'FA',
      color: '#1B5E20',
    },
    {
      name: 'Mohamed Yusuf',
      location: 'Pattinacheri',
      before: 'School dropout at 14 due to inability to afford fees and materials.',
      after: 'Now in Class 11 on full MBAM scholarship, aspires to be an engineer.',
      avatar: 'MY',
      color: '#A88B2A',
    },
    {
      name: 'Zainab & Children',
      location: 'Kottagam',
      before: 'Widowed mother of 4 with no support network after flooding destroyed their home.',
      after: 'Received emergency relief, rebuilt home with community support program.',
      avatar: 'ZC',
      color: '#0D3B0F',
    },
  ];

  return (
    <section id="impact" className="impact-section">
      <div className={`section-header ${isVisible ? 'animate-in' : ''}`} ref={ref}>
        <span>Real People, Real Change</span>
        <h3>Stories of transformation</h3>
        <p className="section-subtext">Every donation is a life changed. Here are just a few of the families you've helped.</p>
      </div>
      <div className="stories-grid">
        {stories.map((s, i) => (
          <div key={i} className={`story-card ${isVisible ? `animate-in delay-${i + 1}` : ''}`}>
            <div className="story-avatar" style={{ background: s.color }}>{s.avatar}</div>
            <div className="story-name">{s.name}</div>
            <div className="story-location">📍 {s.location}</div>
            <div className="story-before">
              <span className="story-label before">Before</span>
              <p>{s.before}</p>
            </div>
            <div className="story-after">
              <span className="story-label after">After</span>
              <p>{s.after}</p>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

// ── Transparency Section ──────────────────────────────────────
const Transparency = () => {
  const [ref, isVisible] = useScrollAnimation();
  const breakdown = [
    { label: 'Direct Programs', pct: 70, color: '#1B5E20', desc: 'Food aid, education, emergency relief' },
    { label: 'Operations', pct: 20, color: '#C9A736', desc: 'Staff, logistics, administration' },
    { label: 'Outreach', pct: 10, color: '#2E7D32', desc: 'Awareness, fundraising, partnerships' },
