// ── Donate Section ────────────────────────────────────────────
const DonateSection = () => {
  const [ref, isVisible] = useScrollAnimation();
  const [selected, setSelected] = useState(50);
  const [custom, setCustom] = useState('');
  const [type, setType] = useState('sadaqah');
  const amounts = [10, 25, 50, 100, 250];
  const impacts = {
    10: 'Provides a meal for a family of 4',
    25: 'Covers school supplies for one child',
    50: 'Feeds a family for one week',
    100: 'Sponsors a student for one month',
    250: 'Covers emergency relief for one family',
  };

  return (
    <section id="donate" className="donate-section">
      <div className={`donate-content ${isVisible ? 'animate-in' : ''}`} ref={ref}>
        <div className="donate-header">
          <span className="donate-eyebrow">Make a Difference Today</span>
          <h3>Your generosity changes lives</h3>
          <p>Every contribution — no matter the size — reaches those who need it most.</p>
        </div>
        <div className="donate-card">
          <div className="donate-type-toggle">
            <button className={type === 'sadaqah' ? 'active' : ''} onClick={() => setType('sadaqah')}>Sadaqah</button>
            <button className={type === 'zakat' ? 'active' : ''} onClick={() => setType('zakat')}>Zakat</button>
            <button className={type === 'waqf' ? 'active' : ''} onClick={() => setType('waqf')}>Waqf</button>
          </div>
          <div className="donate-amounts">
            {amounts.map(amt => (
              <button key={amt} className={`amount-btn ${selected === amt && !custom ? 'active' : ''}`}
                onClick={() => { setSelected(amt); setCustom(''); }}>
                RM {amt}
              </button>
            ))}
            <input
              type="number"
              placeholder="Custom"
              value={custom}
              onChange={e => { setCustom(e.target.value); setSelected(null); }}
              className="amount-custom"
              min="1"
            />
          </div>
          {(selected || custom) && (
            <div className="donate-impact">
              <span>💚</span>
              <span>{impacts[selected] || `RM ${custom} makes a meaningful difference`}</span>
            </div>
          )}
          <a href="#contact" className="btn primary large donate-cta">
            Donate {custom ? `RM ${custom}` : selected ? `RM ${selected}` : ''} as {type.charAt(0).toUpperCase() + type.slice(1)}
          </a>
          <div className="donate-methods">
            <span>💳 Card</span>
            <span>🏦 Bank Transfer</span>
            <span>📱 DuitNow / UPI</span>
          </div>
        </div>
      </div>
    </section>
  );
};

